147     // TODO WE NEED A TEXTURE UNIFORM AS WELL.
148     inline void upload(GLint loc,std::shared_ptr<Texture> tex, int slot = 0){
149         if(tex){
150             tex->bind(slot);
151             glUniform1i(loc, slot);
152             return;
153         }
154 
155         glActiveTexture(GL_TEXTURE0 + slot);
156         glBindTexture(GL_TEXTURE_2D, 0);
157         glUniform1i(loc, slot);
158         return;
159     }
160 
166     inline void upload(GLint loc, const TextureSlot& texSlot){
167         if(texSlot.texture){
168             texSlot.texture->bind(texSlot.slot);
169             glUniform1i(loc, texSlot.slot);
170             return;
171         }
172 
173         glActiveTexture(GL_TEXTURE0 + texSlot.slot);
174         glBindTexture(GL_TEXTURE_2D, 0);
175         glUniform1i(loc, texSlot.slot);
176         return;
177     }
178 
184     inline void upload(GLint loc, const CubeMapSlot& mapSlot){
185         if(mapSlot.cubemap){
186             mapSlot.cubemap->bind(mapSlot.slot);
187             glUniform1i(loc, mapSlot.slot);
188             return;
189         }
190 
191         glActiveTexture(GL_TEXTURE0 + mapSlot.slot);
192         glBindTexture(GL_TEXTURE_CUBE_MAP, 0);
193         glUniform1i(loc, mapSlot.slot);
194         return;
195     }
196 }
