262         GLint getUniformLocationCached(const std::string& name);
263 
269         std::string _generateShaderLog(Shader shader){
270             GLint success;
271             glGetShaderiv(shader, GL_COMPILE_STATUS, &success);
272             if(!success){
273                 char infoLog[1024] = {0};
274                 glGetShaderInfoLog(shader, 512, 0, infoLog);
275                 return std::string(infoLog);
276             }
277             return std::string("Successful Compilation.");
278         }
279 
285         std::string _generateProgramLog(Program shader){
286             GLint success;
287             glGetProgramiv(shader, GL_LINK_STATUS, &success);
288             if (!success) {
289                 char infoLog[1024] = {0};
290                 glGetProgramInfoLog(shader, 1024, NULL, infoLog);
291                 return "Linker Error: " + std::string(infoLog);
292             }
293             return "Program Linked Successfully.";
294         }
295 
302         Shader _createShader(std::string glsl, ShaderType type){
303             Shader value = 0;
304 
305             const char * str = glsl.c_str();
306 
307             switch (type){
308                 case ShaderType::VERTEX:
309                     value = glCreateShader(GL_VERTEX_SHADER);
310                     break;
311                 case ShaderType::FRAGMENT:
312                     value = glCreateShader(GL_FRAGMENT_SHADER);
313                     break;
314                 case ShaderType::GEOMETRY:
315                     value = glCreateShader(GL_GEOMETRY_SHADER);
316                     break;
317                 case ShaderType::TESSELATION:
318                     value = glCreateShader(GL_TESS_CONTROL_SHADER);
319                     break;
320                 case ShaderType::COMPUTE:
321                     value = glCreateShader(GL_COMPUTE_SHADER);
322                     break;
323                 case ShaderType::TASK:
324                     value = glCreateShader(GL_TESS_EVALUATION_SHADER);
325                     break;
326                 case ShaderType::RAYTRACE:
327                 default:
328                     value = 0;
329                     break;
330             }
331 
332             if(value != 0){
333                 glShaderSource(value,1,&str, NULL);
334                 glCompileShader(value);
335             }
336 
337             return value;
338         }
339 
